/**
 * Notification model and related types.
 *
 * Core types for the notification system. All notification adapters
 * and services operate on these types.
 */

/**
 * Supported notification delivery channels.
 * New channels are added here and a corresponding adapter is created.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in-app';

/**
 * Categorizes the kind of notification being sent.
 * Used by adapters to determine formatting and delivery behavior.
 */
export type NotificationType =
  | 'order-confirmation'
  | 'order-status-update'
  | 'user-welcome'
  | 'user-updated'
  | 'system-alert';

/**
 * Priority levels for notification delivery.
 * Adapters may use this to determine delivery urgency.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * The payload passed to notification adapters for delivery.
 *
 * This is the canonical shape that all adapters receive.
 * Adapters transform this into channel-specific formats (e.g., email subject/body).
 */
export interface NotificationPayload {
  /** Unique identifier for this notification */
  id: string;
  /** The type of notification */
  type: NotificationType;
  /** The channel this notification should be delivered through */
  channel: NotificationChannel;
  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
  recipient: string;
  /** Short summary (used as email subject, push title, etc.) */
  subject: string;
  /** Full notification body */
  body: string;
  /** Delivery priority */
  priority: NotificationPriority;
  /** Additional metadata for adapter-specific needs */
  metadata: Record<string, string>;
  /** When the notification was created */
  createdAt: Date;
}

/**
 * Result of a notification delivery attempt.
 */
export interface NotificationResult {
  /** The notification that was sent */
  notificationId: string;
  /** The channel it was delivered through */
  channel: NotificationChannel;
  /** Whether delivery succeeded */
  success: boolean;
  /** Error message if delivery failed */
  error?: string;
  /** When delivery was attempted */
  deliveredAt: Date;
}

/**
 * Input for creating a notification (before ID and timestamp are assigned).
 */
export interface CreateNotificationInput {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  priority?: NotificationPriority;
  metadata?: Record<string, string>;
}

/**
 * NotificationAdapter interface — the contract all notification delivery
 * channels must implement.
 *
 * ARCHITECTURAL CONSTRAINT:
 * All notification channels (email, webhook, SMS, push, etc.) MUST implement
 * this interface. The NotificationService dispatches to adapters solely through
 * this interface. Never bypass it with direct delivery calls.
 *
 * To add a new notification channel:
 * 1. Add the channel name to NotificationChannel in src/models/notification.ts
 * 2. Create an adapter class implementing NotificationAdapter
 * 3. Register the adapter with NotificationService via registerAdapter()
 */

import type {
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Must return a result indicating success or failure — never throw.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;

  /**
   * Check whether this adapter is currently operational.
   * Used for health checks and fallback decisions.
   */
  isAvailable(): Promise<boolean>;
}

/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel.
 * Currently a stub that logs email delivery — replace the send()
 * internals with a real email provider (SendGrid, SES, SMTP, etc.)
 * while keeping the interface contract.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Sender email address (e.g., "noreply@taskflow.io") */
  fromAddress: string;
  /** Sender display name (e.g., "TaskFlow Pro") */
  fromName: string;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sent: NotificationPayload[] = [];

  constructor(private config: EmailConfig) {}

  /**
   * Send an email notification.
   *
   * Currently stores the email in-memory for testing/development.
   * Replace internals with a real provider for production use.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Sending email to ${payload.recipient}: "${payload.subject}"`,
    );

    // Stub: store in memory instead of actually sending
    this.sent.push(payload);

    return {
      notificationId: payload.id,
      channel: 'email',
      success: true,
      deliveredAt: new Date(),
    };
  }

  /**
   * Check if the email adapter is available.
   */
  async isAvailable(): Promise<boolean> {
    // In production, this would check SMTP connection / API key validity
    return true;
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): NotificationPayload[] {
    return [...this.sent];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sent = [];
  }
}

/**
 * Notification service — routes events to notification adapters.
 *
 * ARCHITECTURE:
 * This service uses a purely event-driven pattern. It subscribes to domain
 * events on the EventBus, transforms them into NotificationPayloads, and
 * dispatches them to the appropriate NotificationAdapter.
 *
 * Flow: DomainEvent → EventBus → NotificationService → NotificationAdapter → Delivery
 *
 * CONSTRAINTS:
 * - All notifications MUST originate from EventBus events. No direct calls.
 * - All delivery MUST go through a registered NotificationAdapter.
 * - To add a new notification trigger: subscribe to the event in registerEventHandlers().
 * - To add a new delivery channel: implement NotificationAdapter and register it.
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
  CreateNotificationInput,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset ID counter — for testing only. */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private results: NotificationResult[] = [];

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is supported — later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to domain events that trigger notifications.
   *
   * All notification triggers are centralized here. To add a new trigger,
   * subscribe to the event and call dispatchNotification() with the payload.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) =>
      this.handleOrderCreated(event),
    );

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) =>
      this.handleOrderStatusChanged(event),
    );

    this.eventBus.on<UserCreatedEvent>('user:created', (event) =>
      this.handleUserCreated(event),
    );
  }

  /**
   * Handle order created — send confirmation email.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.dispatchNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      priority: 'normal',
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(
    event: OrderStatusChangedEvent,
  ): Promise<void> {
    await this.dispatchNotification({
      type: 'order-status-update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      priority: 'normal',
    });
  }

  /**
   * Handle user created — send welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.dispatchNotification({
      type: 'user-welcome',
      channel: 'email',
      recipient: event.user.email,
      subject: `Welcome to TaskFlow Pro, ${event.user.name}!`,
      body: `Your account has been created. You can now start managing tasks and orders.`,
      priority: 'normal',
    });
  }

  /**
   * Build a full NotificationPayload from input and dispatch to the appropriate adapter.
   */
  async dispatchNotification(
    input: CreateNotificationInput,
  ): Promise<NotificationResult> {
    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: input.type,
      channel: input.channel,
      recipient: input.recipient,
      subject: input.subject,
      body: input.body,
      priority: input.priority ?? 'normal',
      metadata: input.metadata ?? {},
      createdAt: new Date(),
    };

    const adapter = this.adapters.get(payload.channel);
    if (!adapter) {
      this.logger.warn(
        `No adapter registered for channel "${payload.channel}". Notification ${payload.id} dropped.`,
      );
      const result: NotificationResult = {
        notificationId: payload.id,
        channel: payload.channel,
        success: false,
        error: `No adapter registered for channel: ${payload.channel}`,
        deliveredAt: new Date(),
      };
      this.results.push(result);
      return result;
    }

    const result = await adapter.send(payload);
    this.results.push(result);

    if (result.success) {
      this.logger.info(
        `Notification ${payload.id} delivered via ${payload.channel} to ${payload.recipient}`,
      );
    } else {
      this.logger.error(
        `Notification ${payload.id} failed via ${payload.channel}: ${result.error}`,
      );
    }

    return result;
  }

  /**
   * Get all notification delivery results.
   */
  getResults(): NotificationResult[] {
    return [...this.results];
  }

  /**
   * Get delivery results for a specific channel.
   */
  getResultsByChannel(channel: NotificationChannel): NotificationResult[] {
    return this.results.filter((r) => r.channel === channel);
  }

  /**
   * Get count of delivered notifications.
   */
  getDeliveredCount(): number {
    return this.results.filter((r) => r.success).length;
  }

  /**
   * Get the adapter registered for a given channel, if any.
   */
  getAdapter(channel: NotificationChannel): NotificationAdapter | undefined {
    return this.adapters.get(channel);
  }

  /**
   * Clear all results. Useful for testing.
   */
  clearResults(): void {
    this.results = [];
  }
}

